import { useState, useEffect, lazy, Suspense } from 'react';
import MainLayout from './components/layout/MainLayout';
import Navbar from './components/layout/Navbar';
import Hero from './components/sections/Hero';
import Problem from './components/sections/Problem';
import OperationsExplainer from './components/sections/OperationsExplainer';
import Signs from './components/sections/Signs';
import WhatWeDo from './components/sections/WhatWeDo';
import WhoWeHelp from './components/sections/WhoWeHelp';
import PortfolioProof from './components/sections/PortfolioProof';
import Method from './components/sections/Method';
import Authority from './components/sections/Authority';
import PrivacyTrust from './components/sections/PrivacyTrust';
import Contact from './components/sections/Contact';
import PersonaDrawer from './components/layout/PersonaDrawer';
import { portfolioProjects } from './data/portfolioData';
import { getPersonaBySlug } from './data/personaData';

// ÔöÇÔöÇ Lazy-loaded routes ÔöÇÔöÇ
// Admin, portals, and heavy pages are code-split to reduce the public bundle.
// Only the homepage sections are eagerly loaded (critical rendering path).
const AdminPanel = lazy(() => import('./components/admin/AdminPanel'));
const ClientPortal = lazy(() => import('./components/portal/ClientPortal'));
const ReferralPortal = lazy(() => import('./components/portal/ReferralPortal'));
const AnimationShowcase = lazy(() => import('./components/sections/AnimationShowcase'));
const JobsPage = lazy(() => import('./components/sections/JobsPage'));
const Portfolio = lazy(() => import('./components/sections/Portfolio'));
const ProjectDetail = lazy(() => import('./components/sections/ProjectDetail'));
const DemosPage = lazy(() => import('./components/sections/DemosPage'));
const DemoDetailPage = lazy(() => import('./components/sections/DemoDetailPage'));
const PersonaPage = lazy(() => import('./components/sections/PersonaPage'));
const WhoWeHelpPage = lazy(() => import('./components/sections/WhoWeHelpPage'));

const personaSlugs = ['founders', 'operations', 'product-systems', 'creative-ops', 'ai-adoption', 'remote-owner', 'financial-ops'];

/** Minimal loading fallback for lazy-loaded routes */
const LazyFallback = () => (
  <div className="min-h-screen bg-neutral-950 flex items-center justify-center">
    <div className="flex flex-col items-center gap-3">
      <svg className="animate-spin w-8 h-8 text-[#00bfff]" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round"><path d="M12 2a10 10 0 0 1 10 10" /></svg>
      <span className="text-xs text-neutral-600 font-medium tracking-wider uppercase">Loading</span>
    </div>
  </div>
);

function App() {
  const [currentPath, setCurrentPath] = useState(window.location.pathname);
  const [personaDrawerOpen, setPersonaDrawerOpen] = useState(false);

  useEffect(() => {
    // Handle legacy hash routing for bookmarks (e.g., /#_ops -> /_ops) on mount
    if (window.location.hash && window.location.hash.startsWith('#_')) {
      const cleanPath = '/' + window.location.hash.substring(1);
      window.history.replaceState({}, '', cleanPath);
      setCurrentPath(cleanPath);
    }

    const handleNavigation = () => {
      // Also catch it if they manually type the hash while the app is already running
      if (window.location.hash && window.location.hash.startsWith('#_')) {
        const cleanPath = '/' + window.location.hash.substring(1);
        window.history.replaceState({}, '', cleanPath);
        setCurrentPath(cleanPath);
      } else {
        setCurrentPath(window.location.pathname);
      }
      window.scrollTo(0, 0);
    };
    window.addEventListener('popstate', handleNavigation);
    window.addEventListener('hashchange', handleNavigation); // Add hashchange to be safe
    return () => {
      window.removeEventListener('popstate', handleNavigation);
      window.removeEventListener('hashchange', handleNavigation);
    };
  }, []);

  // ÔöÇÔöÇ Route matching ÔöÇÔöÇ

  if (currentPath === '/_ops' || currentPath.startsWith('/_ops/')) {
    return <Suspense fallback={<LazyFallback />}><AdminPanel /></Suspense>;
  }

  if (currentPath === '/referral') {
    return <Suspense fallback={<LazyFallback />}><ReferralPortal /></Suspense>;
  }

  if (currentPath === '/showcase') {
    return <Suspense fallback={<LazyFallback />}><AnimationShowcase /></Suspense>;
  }

  if (currentPath === '/demos') {
    return (
      <Suspense fallback={<LazyFallback />}>
        <Navbar />
        <DemosPage />
      </Suspense>
    );
  }

  if (currentPath.startsWith('/demo/')) {
    const demoId = currentPath.replace('/demo/', '');
    return (
      <Suspense fallback={<LazyFallback />}>
        <Navbar />
        <DemoDetailPage demoId={demoId} />
      </Suspense>
    );
  }

  if (currentPath === '/jobs' || currentPath.startsWith('/job/') || currentPath.startsWith('/apply/')) {
    return (
      <Suspense fallback={<LazyFallback />}>
        <Navbar />
        <JobsPage />
      </Suspense>
    );
  }

  if (currentPath === '/contact') {
    return (
      <>
        <Navbar />
        <div className="pt-16">
          <Contact />
        </div>
      </>
    );
  }

  if (currentPath === '/portal') {
    return (
      <Suspense fallback={<LazyFallback />}>
        <Navbar />
        <ClientPortal />
      </Suspense>
    );
  }

  if (currentPath === '/portfolio' || currentPath.startsWith('/portfolio?')) {
    return <Suspense fallback={<LazyFallback />}><Portfolio /></Suspense>;
  }

  if (currentPath.startsWith('/project/')) {
    const projectId = currentPath.replace('/project/', '');
    const project = portfolioProjects.find(p => p.id === projectId);
    if (project) {
      return <Suspense fallback={<LazyFallback />}><ProjectDetail project={project} /></Suspense>;
    }
    return <Suspense fallback={<LazyFallback />}><Portfolio /></Suspense>;
  }

  // Persona pages
  const cleanPath = currentPath.replace(/^\//, '');

  if (cleanPath === 'who-we-help') {
    return <Suspense fallback={<LazyFallback />}><WhoWeHelpPage /></Suspense>;
  }

  if (personaSlugs.includes(cleanPath)) {
    const persona = getPersonaBySlug(cleanPath);
    if (persona) {
      return <Suspense fallback={<LazyFallback />}><PersonaPage persona={persona} /></Suspense>;
    }
  }

  // ÔöÇÔöÇ Homepage (eagerly loaded ÔÇö critical path) ÔöÇÔöÇ
  return (
    <MainLayout>
      <Hero />
      <Problem />
      <OperationsExplainer />
      <Signs />
      <WhatWeDo />
      <WhoWeHelp />
      <PortfolioProof />
      <Method />
      <Authority />
      <PrivacyTrust />

      {/* Floating 'Who We Help' trigger */}
      <button
        onClick={() => setPersonaDrawerOpen(true)}
        className="fixed right-0 top-1/2 translate-y-[4px] z-40 bg-neutral-900/90 backdrop-blur-md hover:bg-neutral-800/90 border border-neutral-800 border-r-0 rounded-l-lg px-2 py-3 sm:px-3 sm:py-4 text-neutral-400 hover:text-white transition-all shadow-lg group cursor-pointer"
        aria-label="Open Who We Help drawer"
      >
        <span className="text-[10px] sm:text-xs font-bold uppercase tracking-wider [writing-mode:vertical-lr] rotate-180">Who We Help</span>
      </button>

      <PersonaDrawer isOpen={personaDrawerOpen} onClose={() => setPersonaDrawerOpen(false)} />
    </MainLayout>
  );
}

export default App;

import { useState, useCallback, type ReactNode } from 'react'

/**
 * Inline SVG spinner ÔÇö no emoji, no Lucide dependency.
 * Renders a small animated ring matching the current text color.
 */
function Spinner({ size = 16 }: { size?: number }) {
  return (
    <svg
      className="animate-spin"
      width={size}
      height={size}
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="2.5"
      strokeLinecap="round"
    >
      <path d="M12 2a10 10 0 0 1 10 10" />
    </svg>
  )
}

/**
 * ActionButton ÔÇö drop-in replacement for any async button.
 * Shows a spinner while the onClick handler resolves.
 * 
 * @example
 * <ActionButton onClick={handleSave} className="...">Save</ActionButton>
 */
export function ActionButton({
  onClick,
  children,
  className = '',
  disabled = false,
  type = 'button',
  busyText,
  spinnerSize = 14,
}: {
  onClick?: (e: React.MouseEvent) => Promise<any> | void
  children: ReactNode
  className?: string
  disabled?: boolean
  type?: 'button' | 'submit'
  busyText?: string
  spinnerSize?: number
}) {
  const [busy, setBusy] = useState(false)

  const handleClick = useCallback(async (e: React.MouseEvent) => {
    if (busy || disabled || !onClick) return
    const result = onClick(e)
    if (result && typeof (result as any).then === 'function') {
      setBusy(true)
      try { await result } finally { setBusy(false) }
    }
  }, [onClick, busy, disabled])

  const isBusy = busy
  const isDisabled = disabled || isBusy

  return (
    <button
      type={type}
      onClick={type === 'submit' ? undefined : handleClick}
      disabled={isDisabled}
      className={`${className} ${isDisabled ? 'opacity-50 pointer-events-none' : ''}`}
    >
      {isBusy ? (
        <span className="inline-flex items-center gap-1.5">
          <Spinner size={spinnerSize} />
          {busyText || null}
        </span>
      ) : children}
    </button>
  )
}

/**
 * FormButton ÔÇö for submit buttons inside <form> elements.
 * Wraps the form's onSubmit and shows spinner while resolving.
 * Use the `busy` prop to control externally.
 */
export function FormButton({
  children,
  className = '',
  busy = false,
  disabled = false,
  busyText,
  spinnerSize = 14,
}: {
  children: ReactNode
  className?: string
  busy?: boolean
  disabled?: boolean
  busyText?: string
  spinnerSize?: number
}) {
  const isDisabled = disabled || busy

  return (
    <button
      type="submit"
      disabled={isDisabled}
      className={`${className} ${isDisabled ? 'opacity-50 pointer-events-none' : ''}`}
    >
      {busy ? (
        <span className="inline-flex items-center gap-1.5">
          <Spinner size={spinnerSize} />
          {busyText || 'Working...'}
        </span>
      ) : children}
    </button>
  )
}

/**
 * Hook for wrapping any async action with loading state.
 * Returns [handler, isBusy] tuple.
 */
// eslint-disable-next-line react-refresh/only-export-components -- hook export alongside components is intentional
export function useAsyncAction<T extends (...args: any[]) => Promise<any>>(
  action: T
): [(...args: Parameters<T>) => Promise<ReturnType<T>>, boolean] {
  const [busy, setBusy] = useState(false)

  const wrapped = useCallback(async (...args: Parameters<T>) => {
    setBusy(true)
    try {
      return await action(...args)
    } finally {
      setBusy(false)
    }
  }, [action]) as (...args: Parameters<T>) => Promise<ReturnType<T>>

  return [wrapped, busy]
}

import { useEffect } from 'react'
import { useAdminStore, adminActions } from '../../store/useAdminStore'
import AdminLogin from './AdminLogin'
import DashboardSection from './DashboardSection'
import SettingsSection from './SettingsSection'
import { ProjectsSection, InvoicesSection, CareersSection, ReferralsSection, UsersSection, LogsSection, SLASection } from './AdminSections'
import CRMSection from './CRMSection'
import ProfileSection from './ProfileSection'
import ReferralPortal from '../portal/ReferralPortal'
import ClientPortal from '../portal/ClientPortal'
import { LayoutDashboard, BarChart3, Users, FolderOpen, FileText, Briefcase, UserCheck, Shield, Settings, Activity, Clock, LogOut, Eye, UserCircle, X, BookOpen, Globe, Mail, GraduationCap, Phone, Bell, AlertTriangle } from 'lucide-react'
import { useState } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import OnboardingChecklist from './OnboardingChecklist'
import EcosystemSection from './EcosystemSection'
import MailSection from './MailSection'
import StarterclassSection from './StarterclassSection'
import CallSection from './CallSection'
import AnalyticsSection from './AnalyticsSection'
import VercelAdminShell from './vercel/VercelAdminShell'
import MeetingsSection from './MeetingsSection'
import NewProjectSection from './NewProjectSection'
import ContractsSection from './ContractsSection'

const NAV = [
  { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
  { id: 'analytics', label: 'Analytics', icon: BarChart3 },
  { id: 'mail', label: 'Mail', icon: Mail },
  { id: 'calls', label: 'Calls', icon: Phone },
  { id: 'meetings', label: 'Meetings', icon: Clock },
  { id: 'clients', label: 'Clients', icon: Users },
  { id: 'referrals', label: 'Referrals', icon: UserCheck },
  { id: 'invoices', label: 'Invoices', icon: FileText },
  { id: 'sla', label: 'SLA', icon: Clock },
  { id: 'new-project', label: 'New Project', icon: FolderOpen },
  { id: 'contracts', label: 'Contracts', icon: Briefcase },
  { id: 'users', label: 'Team', icon: Shield },
  { id: 'ecosystem', label: 'Ecosystem', icon: Globe },
  { id: 'starterclass', label: 'Starterclass', icon: GraduationCap },
  { id: 'projects', label: 'Projects', icon: FolderOpen },
  { id: 'careers', label: 'Careers', icon: Briefcase },
  { id: 'logs', label: 'Logs', icon: Activity },
  { id: 'settings', label: 'Settings', icon: Settings },
]

export default function AdminPanel() {
  const { token, user, activeSection, actingAs, impersonating, users, slaNotifications } = useAdminStore()
  const [collapsed, setCollapsed] = useState(false)
  const [showActAs, setShowActAs] = useState(false)
  const [showImpersonate, setShowImpersonate] = useState(false)
  const [showOnboarding, setShowOnboarding] = useState(false)
  const [mobileOpen, setMobileOpen] = useState(false)
  const [showNotifs, setShowNotifs] = useState(false)
  const [adminTheme, setAdminTheme] = useState(() =>
    localStorage.getItem('icuni_admin_theme') || 'modern'
  )

  // ÔöÇÔöÇ Session validation ÔÇö must be called before any early returns (React hook rules) ÔöÇÔöÇ
  useEffect(() => { adminActions.validateSession() }, [])
  useEffect(() => { if (token) adminActions.loadSlaNotifications() }, [token])

  // ÔöÇÔöÇ Modern Theme Routing ÔöÇÔöÇ
  // If Modern theme selected, delegate entirely to VercelAdminShell
  if (adminTheme === 'modern') {
    return <VercelAdminShell onSwitchTheme={() => {
      localStorage.setItem('icuni_admin_theme', 'classic')
      setAdminTheme('classic')
    }} />
  }

  // ÔöÇÔöÇ Classic Theme below ÔÇö entirely unchanged ÔöÇÔöÇ

  // Not logged in or not admin
  if (!token || !user) return <AdminLogin />

  // ÔöÇÔöÇ Role Helpers ÔöÇÔöÇ
  const role = user.role || ''
  const isElevated = ['Godmode', 'SuperAdmin'].includes(role) // Can manage team + ecosystem
  const userPerms = user.permissions || {}

  // Department scope mapping (frontend mirror of backend DEPARTMENT_SCOPE)
  const DEPT_SCOPE: Record<string, string[]> = {
    'Admin':      ['dashboard', 'mail', 'clients', 'meetings', 'referrals', 'invoices', 'sla', 'new-project', 'contracts', 'ecosystem', 'projects', 'settings'],
    'Sales':      ['dashboard', 'mail', 'clients', 'meetings', 'referrals'],
    'Product':    ['dashboard', 'mail', 'new-project', 'contracts', 'ecosystem', 'sla']
  }

  // Filter nav items based on role + permissions
  const filteredNav = NAV.filter(item => {
    // Godmode sees everything
    if (role === 'Godmode') return true
    // Team + Ecosystem are elevated-only
    if (item.id === 'users') return isElevated
    if (item.id === 'ecosystem') return isElevated
    if (item.id === 'starterclass') return isElevated
    // Careers + Logs are Godmode-only
    if (item.id === 'careers') return false
    if (item.id === 'logs') return false
    // SuperAdmin gets the curated menu
    if (role === 'SuperAdmin') return true
    // Check department scope first, then permission overrides
    const deptSections = DEPT_SCOPE[role] || []
    const inScope = deptSections.includes(item.id)
    // Permission toggles can override scope (admin can restrict further)
    if (userPerms[item.id] === false) return false
    return inScope
  })

  // ÔöÇÔöÇ Act As: render target portal ÔöÇÔöÇ
  if (actingAs === 'referrer') {
    return (
      <>
        <ActingAsBanner role="Referrer" />
        <ReferralPortal demoMode />
      </>
    )
  }
  if (actingAs === 'client') {
    return (
      <>
        <ActingAsBanner role="Client" />
        <ClientPortal demoMode />
      </>
    )
  }

  const sidebarWidth = collapsed ? 64 : 240

  const renderSection = () => {
    switch (activeSection) {
      case 'dashboard': return <DashboardSection />
      case 'analytics': return <AnalyticsSection />
      case 'mail': return <MailSection />
      case 'clients': return <CRMSection />
      case 'projects': return <ProjectsSection />
      case 'invoices': return <InvoicesSection />
      case 'careers': return <CareersSection />
      case 'referrals': return <ReferralsSection />
      case 'sla': return <SLASection />
      case 'users': return <UsersSection />
      case 'logs': return <LogsSection />
      case 'settings': return <SettingsSection />
      case 'profile': return <ProfileSection />
      case 'ecosystem': return <EcosystemSection />
      case 'starterclass': return <StarterclassSection />
      case 'calls': return <CallSection />
      case 'meetings': return <MeetingsSection />
      case 'new-project': return <NewProjectSection />
      case 'contracts': return <ContractsSection />
      default: return <DashboardSection />
    }
  }

  // Close mobile sidebar when section changes
  const handleNavClick = (id: string) => {
    adminActions.setSection(id)
    adminActions.setError('')  // Clear stale errors on nav
    setMobileOpen(false)
  }

  // Profile picture helper ÔÇö show impersonated user when active
  const effectiveUser = impersonating || user
  const userPic = effectiveUser?.profile_pic_url || ''

  return (
    <div className="min-h-screen bg-neutral-950">
      {/* Mobile overlay */}
      {mobileOpen && (
        <div className="fixed inset-0 bg-black/60 z-40 md:hidden" onClick={() => setMobileOpen(false)} />
      )}

      {/* Mobile hamburger button */}
      <button
        onClick={() => setMobileOpen(!mobileOpen)}
        className="fixed top-3 left-3 z-50 md:hidden w-10 h-10 flex items-center justify-center rounded-xl bg-neutral-900 border border-neutral-800 text-neutral-400 hover:text-white transition-all cursor-pointer"
      >
        {mobileOpen ? <X className="w-5 h-5" /> : (
          <svg className="w-5 h-5" viewBox="0 0 20 20" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round">
            <path d="M3 5h14M3 10h14M3 15h14" />
          </svg>
        )}
      </button>

      {/* Fixed Sidebar */}
      <aside
        className={`fixed top-0 left-0 h-screen bg-neutral-900/80 backdrop-blur-md border-r border-neutral-800 flex z-40 transition-all duration-200
          ${mobileOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}
        style={{ width: sidebarWidth }}
      >
        {/* Sidebar Content */}
        <div className="flex flex-col flex-1 min-w-0">
          {/* Logo */}
          <div className="h-16 flex items-center gap-3 px-4 border-b border-neutral-800 shrink-0">
            <img src="/icuni_logo.webp" alt="ICUNI" className="w-8 h-8 rounded-md object-contain shrink-0" />
            {!collapsed && <span className="font-bold text-sm text-white tracking-tight">Ops Console</span>}
          </div>

          {/* Nav */}
          <nav className="flex-1 py-3 px-2 space-y-0.5 overflow-y-auto">
            {filteredNav.map(item => {
              const active = activeSection === item.id
              return (
                <motion.button key={item.id} onClick={() => handleNavClick(item.id)}
                  whileTap={{ scale: 0.95 }}
                  className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-all cursor-pointer group ${
                    active
                      ? 'bg-[#00bfff]/10 text-[#00bfff] border border-[#00bfff]/20'
                      : 'text-neutral-500 hover:text-white hover:bg-neutral-800/50 border border-transparent'
                  }`}>
                  <motion.div
                    animate={active ? {
                      scale: [1, 1.15, 1],
                      rotate: [0, -8, 8, 0],
                    } : {}}
                    transition={active ? {
                      duration: 2,
                      repeat: Infinity,
                      repeatDelay: 3,
                      ease: 'easeInOut',
                    } : {}}
                    whileHover={{
                      y: [0, -3, 0],
                      transition: { duration: 0.4, ease: 'easeOut' },
                    }}
                    whileTap={{
                      scale: 0.8,
                      rotate: -12,
                      transition: { duration: 0.15 },
                    }}
                    className="shrink-0"
                  >
                    <item.icon className={`w-[18px] h-[18px] ${active ? 'text-[#00bfff]' : 'group-hover:text-white transition-colors'}`} />
                  </motion.div>
                  {!collapsed && item.label}
                </motion.button>
              )
            })}
          </nav>

          {/* Bottom ÔÇö Profile + Actions */}
          <div className="border-t border-neutral-800 p-3 space-y-2 shrink-0">
            {/* Profile button with picture */}
            <button
              onClick={() => handleNavClick('profile')}
              className={`w-full flex items-center gap-3 rounded-lg hover:bg-neutral-800/50 transition-all cursor-pointer group ${collapsed ? 'justify-center py-2' : 'px-2 py-2.5 text-left'}`}
              title="Profile"
            >
              {/* Profile picture circle */}
              <div className="w-8 h-8 rounded-full overflow-hidden bg-neutral-800 shrink-0 border-2 border-neutral-700 group-hover:border-[#00bfff]/40 transition-colors">
                {userPic ? (
                  <img src={userPic} alt="" className="w-full h-full object-cover" />
                ) : (
                  <div className="w-full h-full flex items-center justify-center bg-gradient-to-br from-[#00bfff]/20 to-[#ff7a00]/20">
                    <svg className="w-4 h-4 text-neutral-500" viewBox="0 0 20 20" fill="none"><circle cx="10" cy="7" r="3.5" stroke="currentColor" strokeWidth="1.3"/><path d="M3.5 17c0-3.6 2.9-6.5 6.5-6.5s6.5 2.9 6.5 6.5" stroke="currentColor" strokeWidth="1.3" strokeLinecap="round"/></svg>
                  </div>
                )}
              </div>
              {!collapsed && (
                <div className="min-w-0 flex-1">
                  <div className="text-xs text-white font-medium truncate group-hover:text-[#00bfff] transition-colors">{effectiveUser?.name || user.name}</div>
                  <div className="text-[10px] text-neutral-600 truncate">{effectiveUser?.email || user.email}</div>
                </div>
              )}
            </button>

            <button onClick={() => setShowOnboarding(true)}
              className="w-full flex items-center gap-2 px-3 py-2 rounded-lg text-neutral-600 hover:text-[#ff7a00] hover:bg-[#ff7a00]/5 text-xs transition-all cursor-pointer border border-transparent hover:border-[#ff7a00]/20">
              <BookOpen className="w-4 h-4" />{!collapsed && 'Onboarding'}
            </button>
            <button onClick={() => { localStorage.setItem('icuni_admin_theme', 'modern'); setAdminTheme('modern') }}
              className="w-full flex items-center gap-2 px-3 py-2 rounded-lg text-neutral-600 hover:text-[#00bfff] hover:bg-[#00bfff]/5 text-xs transition-all cursor-pointer border border-transparent hover:border-[#00bfff]/20">
              <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><rect x="2" y="6" width="20" height="12" rx="2" /><circle cx="8" cy="12" r="2" /><path d="M14 10h4M14 14h4" /></svg>
              {!collapsed && 'Modern View'}
            </button>
