            </div>
          </div>
        </div>
      )}

      {/* Impersonating Banner */}
      {impersonating && (
        <div className="fixed top-0 left-0 right-0 z-[60] flex items-center justify-center gap-3 py-2 bg-gradient-to-r from-purple-600/90 to-[#00bfff]/90 backdrop-blur-sm">
