            <h3>Call Outcome</h3>
            {collapsed.outcome ? <ChevronDown className="w-4 h-4 text-neutral-600" /> : <ChevronUp className="w-4 h-4 text-neutral-600" />}
          </div>
          {!collapsed.outcome && (
            <div className="cg-section-body">
              {OUTCOMES.map(o => (
                <div key={o.id}>
                  <div className={`cg-outcome ${outcome === o.id ? 'selected' : ''}`} onClick={() => setOutcome(o.id)}>
                    <div className="cg-outcome-dot" />
                    <div>
                      <div className="cg-outcome-label">{o.label}</div>
                      <div className="cg-outcome-desc">{o.desc}</div>
                    </div>
                  </div>
                  {outcome === o.id && (o.hasDatetime || o.hasDate || o.hasNotes) && (
                    <div className="cg-data-field mb-3">
                      {(o.hasDatetime || o.hasDate) && (
                        <div className={o.hasDatetime ? 'cg-data-row' : ''}>
                          <div className="mb-2"><label>Date</label><input type="date" value={outcomeDate} onChange={e => setOutcomeDate(e.target.value)} /></div>
                          {o.hasDatetime && <div className="mb-2"><label>Time</label><input type="time" value={outcomeTime} onChange={e => setOutcomeTime(e.target.value)} /></div>}
                        </div>
                      )}
                      {o.hasNotes && <div><label>Notes</label><textarea value={outcomeNotes} onChange={e => setOutcomeNotes(e.target.value)} rows={2} placeholder="Additional detailsÔÇª" /></div>}
                    </div>
                  )}
                </div>
              ))}
              <div className="mt-3">
                <label className="text-[10px] text-neutral-600 font-bold uppercase tracking-wider block mb-2">Call Notes (freeform)</label>
                <textarea value={callNotes} onChange={e => setCallNotes(e.target.value)} rows={3}
                  className="w-full px-3 py-2 bg-neutral-900/60 border border-neutral-800 rounded-lg text-white text-sm placeholder-neutral-600 resize-y"
                  placeholder="Anything that didn't fit the structured fieldsÔÇª" />
              </div>
            </div>
          )}
        </div>

        {/* Live Transcript ÔÇö compact inline panel */}
        {speechSupported && (transcriptLines.length > 0 || isTranscribing) && (
          <div className="cg-section">
            <div className="cg-section-header" onClick={() => toggleSection('transcript')}>
              <h3 className="flex items-center gap-2">
                {isTranscribing && <div className="cg-mic-pulse" />}
                Live Transcript
              </h3>
              <div className="flex items-center gap-2">
                {transcriptLines.length > 0 && (
                  <span className="cg-section-count">{transcriptLines.length} lines</span>
                )}
                {collapsed.transcript ? <ChevronDown className="w-4 h-4 text-neutral-600" /> : <ChevronUp className="w-4 h-4 text-neutral-600" />}
              </div>
            </div>
            {!collapsed.transcript && (
              <div className="cg-section-body">
                {(transcriptLines.length > 0 || interimText) && (
                  <div className="cg-transcript-area" ref={transcriptAreaRef}>
                    {transcriptLines.map((line, i) => (
                      <div key={i} className="cg-transcript-line">
                        <span className="cg-transcript-time">{line.time}</span>
                        <span className="cg-transcript-text">{line.text}</span>
                      </div>
                    ))}
                    {interimText && (
                      <div className="cg-transcript-line">
                        <span className="cg-transcript-time">ÔÇª</span>
                        <span className="cg-transcript-text cg-transcript-interim">{interimText}</span>
                      </div>
                    )}
                  </div>
                )}
                {/* Editable full transcript */}
                {transcriptLines.length > 0 && !isTranscribing && (
                  <div className="mt-3">
                    <label className="text-[10px] text-neutral-600 font-bold uppercase tracking-wider block mb-1">Edit Transcript (corrections welcome)</label>
                    <textarea
                      className="cg-transcript-edit"
                      value={transcript}
                      onChange={e => setTranscript(e.target.value)}
                      rows={6}
                      placeholder="Transcript will appear hereÔÇª"
                    />
                  </div>
                )}
              </div>
            )}
          </div>
        )}
        {/* Section 6: Next Action */}
        {outcome && (
          <div className="cg-section">
            <div className="cg-section-header"><h3>Next Action</h3></div>
            <div className="cg-section-body">
              <div className="cg-next-action">
                <p className="text-sm text-emerald-400 font-semibold mb-2">{getNextAction() || 'Select an outcome above'}</p>
                <label className="text-[10px] text-neutral-600 font-bold uppercase tracking-wider block mb-1">Adjust / Add Notes</label>
                <input value={nextActionNotes} onChange={e => setNextActionNotes(e.target.value)}
                  className="w-full px-3 py-2 bg-neutral-900/60 border border-neutral-800 rounded-lg text-white text-sm placeholder-neutral-600"
                  placeholder="Override or add context to the next actionÔÇª" />
              </div>
            </div>
          </div>
        )}

        {/* Bottom Action Buttons */}
        <div className="flex gap-3 mb-8">
          <button onClick={() => {
            const startTime = callStart ? new Date(callStart).getTime() : Date.now()
            adminActions.minimiseCall(client, startTime)
            if (onMinimise) onMinimise()
            else onClose()
          }}
            className="flex-1 py-3.5 rounded-xl font-bold text-sm bg-neutral-800 border border-neutral-700 text-neutral-400 cursor-pointer hover:bg-neutral-700 hover:text-white transition-all flex items-center justify-center gap-2">
            <svg width="14" height="14" viewBox="0 0 24 24" fill="currentColor"><rect x="6" y="4" width="4" height="16" rx="1" /><rect x="14" y="4" width="4" height="16" rx="1" /></svg>
            Pause Call
          </button>
          <button onClick={() => setShowDiscardConfirm(true)}
            className="flex-1 py-3.5 rounded-xl font-bold text-sm bg-neutral-900 border border-red-500/20 text-red-400 cursor-pointer hover:bg-red-500/10 hover:border-red-500/40 transition-all flex items-center justify-center gap-2">
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="18" y1="6" x2="6" y2="18" /><line x1="6" y1="6" x2="18" y2="18" /></svg>
            Discard
          </button>
          <button onClick={handleSave} disabled={saving || !outcome}
            className="flex-[2] py-3.5 rounded-xl font-bold text-sm bg-gradient-to-r from-[#00bfff] to-[#0099cc] text-white cursor-pointer disabled:opacity-30 disabled:cursor-not-allowed hover:shadow-[0_0_20px_rgba(0,191,255,0.3)] transition-all flex items-center justify-center gap-2">
            {saving ? (<><svg className="animate-spin w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round"><path d="M12 2a10 10 0 0 1 10 10" /></svg>SavingÔÇª</>) : 'End Call & Save'}
          </button>
        </div>

        {/* Discard Confirmation */}
        {showDiscardConfirm && (
          <div className="fixed inset-0 z-[60] bg-black/60 backdrop-blur-sm flex items-center justify-center p-4" onClick={() => setShowDiscardConfirm(false)}>
            <div className="bg-neutral-950 border border-neutral-800 rounded-2xl p-6 w-full max-w-sm shadow-2xl" onClick={e => e.stopPropagation()}>
              <h3 className="text-lg font-bold text-white mb-2">Discard this call?</h3>
              <p className="text-sm text-neutral-400 mb-5">All progress, notes, and data captured during this call will be lost. This cannot be undone.</p>
              <div className="flex gap-3">
                <button onClick={() => setShowDiscardConfirm(false)}
                  className="flex-1 py-2.5 rounded-lg font-bold text-sm bg-neutral-800 text-neutral-300 cursor-pointer hover:bg-neutral-700 transition-all">Keep Going</button>
                <button onClick={onClose}
                  className="flex-1 py-2.5 rounded-lg font-bold text-sm bg-red-500/15 border border-red-500/30 text-red-400 cursor-pointer hover:bg-red-500/25 transition-all">Discard Call</button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  )
}

import { useEffect, useState, useMemo, useRef, useCallback } from 'react'
import { resolveStaffName } from '../../utils/resolveStaffName'
import { useAdminStore, adminActions, useEffectiveUser } from '../../store/useAdminStore'
import { Phone, TrendingUp, Users, Clock, Target, BarChart3, ChevronDown, Download, Calendar, Filter, FileText, Pencil, ArrowRight, Bell, X, AlertTriangle, MessageSquareText } from 'lucide-react'
import CallGuide from './CallGuide'
import '../admin/crm.css'

const PATH_LABELS: Record<string, string> = {
  wc_receptionist: 'WC Receptionist',
  wc_decision_maker: 'WC Decision-Maker',
  bc_front_desk: 'BC Front Desk',
  bc_mr_cooper: 'BC Mr Cooper',
  bc_owner: 'BC Owner',
}

const OUTCOME_LABELS: Record<string, string> = {
  meeting_booked: 'Meeting Booked',
  callback_scheduled: 'Callback Scheduled',
  interested_will_revert: 'Interested',
  no_interest: 'No Interest',
  needs_follow_up: 'Follow-Up',
}

function fmtDuration(sec: number) {
  if (!sec) return '0:00'
  const m = Math.floor(sec / 60), s = sec % 60
  return `${m}:${s.toString().padStart(2, '0')}`
}

function fmtDate(d: string) {
  if (!d) return 'ÔÇö'
  try { return new Date(d).toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric', hour: '2-digit', minute: '2-digit' }) } catch { return d }
}

type DateFilter = 'today' | 'yesterday' | 'this_week' | 'last_week' | 'this_month' | 'this_year' | 'all' | 'custom'

export default function CallSection() {
  const { callLogs: rawCallLogs, clients } = useAdminStore()
  const effectiveUser = useEffectiveUser()
  const isSalesOnly = effectiveUser?.role === 'Sales'

  // Sales associates only see their own calls; everyone else sees all
  const callLogs = useMemo(() => {
    if (!rawCallLogs) return []
    if (isSalesOnly && effectiveUser?.email) {
      return rawCallLogs.filter((l: any) => l.caller_email === effectiveUser.email)
    }
    return rawCallLogs
  }, [rawCallLogs, isSalesOnly, effectiveUser?.email])
  const [activeTab, setActiveTab] = useState<'overview' | 'logs' | 'transcripts' | 'upcoming'>('overview')
  const [dateFilter, setDateFilter] = useState<DateFilter>('this_week')
  const [customStart, setCustomStart] = useState('')
  const [customEnd, setCustomEnd] = useState('')
  const [expandedLog, setExpandedLog] = useState<string | null>(null)
  const [outcomeFilter, setOutcomeFilter] = useState<string | null>(null)

  // Call Picker State
  const [showCallPicker, setShowCallPicker] = useState(false)
  const [callGuideClient, setCallGuideClient] = useState<any>(null)
  const callPickerRef = useRef<HTMLDivElement>(null)

  // Toast & Countdown State
  const [toasts, setToasts] = useState<{ id: string; clientName: string; date: string; clientId: string }[]>([])
  const dismissedToasts = useRef(new Set<string>())
  const [_tick, setTick] = useState(0)

  useEffect(() => {
    adminActions.loadCallLogs({ page_size: 500 })
    adminActions.loadCompetitorIntel()
    adminActions.loadClients()
  }, [])

  // Live ticker for countdown timers
  useEffect(() => {
    const t = setInterval(() => setTick(x => x + 1), 1000)
    return () => clearInterval(t)
  }, [])

  // ÔöÇÔöÇ Upcoming Calls (includes overdue backlog) ÔöÇÔöÇ
  const upcomingCalls = useMemo(() => {
    const now = Date.now()
    const clientMap: Record<string, any> = {}
    ;(clients || []).forEach((c: any) => { clientMap[c.client_id] = c })

    // Collect all next_action_date entries with actionable outcomes, deduplicated by client_id (keep nearest)
    const byClient: Record<string, any> = {}
    ;(callLogs || []).forEach((log: any) => {
      if (!log.next_action_date || !log.client_id) return
      if (!['callback_scheduled', 'needs_follow_up', 'meeting_booked'].includes(log.outcome)) return
      const d = new Date(log.next_action_date).getTime()
      if (isNaN(d)) return
      // Keep the most recent (closest to now) entry per client
      if (!byClient[log.client_id] || Math.abs(d - now) < Math.abs(new Date(byClient[log.client_id].next_action_date).getTime() - now)) {
        byClient[log.client_id] = log
      }
    })

    return Object.values(byClient)
      .map((log: any) => {
        const client = clientMap[log.client_id] || {}
        const actionTime = new Date(log.next_action_date).getTime()
        const diff = actionTime - now
        const isOverdue = actionTime < now
        return { ...log, client, diff, isOverdue, clientName: client.name || client.company || log.client_name || 'Unknown' }
      })
      // Sort: overdue first (most overdue at top), then future by soonest
      .sort((a: any, b: any) => {
        if (a.isOverdue && !b.isOverdue) return -1
        if (!a.isOverdue && b.isOverdue) return 1
        if (a.isOverdue && b.isOverdue) return new Date(a.next_action_date).getTime() - new Date(b.next_action_date).getTime()
        return a.diff - b.diff
      })
  }, [callLogs, clients, _tick])

  // ÔöÇÔöÇ Toast Notifications (fire when Ôëñ 15min away) ÔöÇÔöÇ
  const dismissToast = useCallback((id: string) => {
    dismissedToasts.current.add(id)
    setToasts(prev => prev.filter(t => t.id !== id))
  }, [])

  useEffect(() => {
    const now = Date.now()
    const newToasts: typeof toasts = []
    upcomingCalls.forEach((call: any) => {
      const diff = new Date(call.next_action_date).getTime() - now
      if (diff > 0 && diff <= 15 * 60 * 1000 && !dismissedToasts.current.has(call.call_id)) {
        newToasts.push({ id: call.call_id, clientName: call.clientName, date: call.next_action_date, clientId: call.client_id })
      }
    })
    if (newToasts.length > 0) {
      setToasts(prev => {
        const ids = new Set(prev.map(t => t.id))
        const fresh = newToasts.filter(t => !ids.has(t.id))
        return fresh.length > 0 ? [...prev, ...fresh] : prev
      })
    }
  }, [upcomingCalls])

  // Auto-dismiss toasts after 30s
  useEffect(() => {
    if (toasts.length === 0) return
    const timers = toasts.map(t => setTimeout(() => dismissToast(t.id), 30000))
    return () => timers.forEach(clearTimeout)
  }, [toasts, dismissToast])

  // Close picker on outside click
  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (callPickerRef.current && !callPickerRef.current.contains(e.target as Node)) {
        setShowCallPicker(false)
      }
    }
    document.addEventListener('mousedown', handleClickOutside)
    return () => document.removeEventListener('mousedown', handleClickOutside)
  }, [])

  const handleEditClient = (clientId: string, e?: React.MouseEvent) => {
    if (e) e.stopPropagation()
    const client = clients?.find((c: any) => c.client_id === clientId)
    if (client) {
      // @ts-ignore
      if (adminActions.setActiveClientOptimistic) adminActions.setActiveClientOptimistic(client)
      // @ts-ignore
      if (adminActions.setSection) adminActions.setSection('clients')
    }
  }

  // ÔöÇÔöÇ Date Filtering Logic ÔöÇÔöÇ
  const filteredLogs = useMemo(() => {
    const now = new Date()
    const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate())

    let start: Date | null = null
    let end: Date | null = null

    switch (dateFilter) {
      case 'today':
        start = todayStart
        end = new Date(todayStart.getTime() + 86400000)
        break
      case 'yesterday':
        start = new Date(todayStart.getTime() - 86400000)
        end = todayStart
        break
      case 'this_week': {
        const day = now.getDay() || 7 // Mon=1, Sun=7
        start = new Date(todayStart.getTime() - (day - 1) * 86400000)
        end = new Date(start.getTime() + 7 * 86400000)
        break
      }
      case 'last_week': {
        const day = now.getDay() || 7
        const thisWeekStart = new Date(todayStart.getTime() - (day - 1) * 86400000)
        start = new Date(thisWeekStart.getTime() - 7 * 86400000)
        end = thisWeekStart
        break
      }
      case 'this_month':
        start = new Date(now.getFullYear(), now.getMonth(), 1)
        end = new Date(now.getFullYear(), now.getMonth() + 1, 1)
        break
      case 'this_year':
        start = new Date(now.getFullYear(), 0, 1)
        end = new Date(now.getFullYear() + 1, 0, 1)
        break
      case 'custom':
        if (customStart) start = new Date(customStart)
        if (customEnd) {
          end = new Date(customEnd)
          end.setDate(end.getDate() + 1) // include end day
        }
        break
    }

    if (!start && !end) {
      if (outcomeFilter) return callLogs.filter((log: any) => log.outcome === outcomeFilter)
      return callLogs
    }

    return callLogs.filter(log => {
      const d = new Date(log.call_start)
      if (start && d < start) return false
      if (end && d >= end) return false
      if (outcomeFilter && log.outcome !== outcomeFilter) return false
      return true
    })
  }, [callLogs, dateFilter, customStart, customEnd, outcomeFilter])

  // ÔöÇÔöÇ Client-Side Analytics ÔöÇÔöÇ
  const analytics = useMemo(() => {
    let totalDuration = 0
    let meetings = 0
    const paths: Record<string, number> = {}
    const pathMeetings: Record<string, number> = {}
    const outcomes: Record<string, number> = {}
    const callers: Record<string, { calls: number; meetings: number; name: string }> = {}

    filteredLogs.forEach(log => {
      totalDuration += Number(log.duration_seconds || 0)
      if (log.outcome === 'meeting_booked') meetings++

      // Outcomes
      const out = log.outcome || 'unknown'
      outcomes[out] = (outcomes[out] || 0) + 1

      // Paths
      const p = log.path_loaded || 'unknown'
      paths[p] = (paths[p] || 0) + 1
      if (log.outcome === 'meeting_booked') {
        pathMeetings[p] = (pathMeetings[p] || 0) + 1
      }

      // Callers
      const caller = log.caller_email || 'unknown'
      if (!callers[caller]) {
        callers[caller] = { calls: 0, meetings: 0, name: log.caller_name || caller }
      }
      callers[caller].calls++
      if (log.outcome === 'meeting_booked') callers[caller].meetings++
    })

    const avgDuration = filteredLogs.length ? Math.round(totalDuration / filteredLogs.length) : 0

    // Conversion by Path
    const conversionByPath = Object.keys(paths).map(p => ({
      path: p,
      calls: paths[p],
      meetings: pathMeetings[p] || 0,
      rate: paths[p] ? Math.round(((pathMeetings[p] || 0) / paths[p]) * 100) : 0
    })).sort((a, b) => b.rate - a.rate)

    // Leaderboard
    const leaderboard = Object.values(callers).map(c => ({
      ...c,
      conversionRate: c.calls ? Math.round((c.meetings / c.calls) * 100) : 0
    })).sort((a, b) => b.meetings - a.meetings || b.calls - a.calls)

    // Daily attempt/conversation targets (computed from today's calls in all logs)
    const todayStart = new Date()
    todayStart.setHours(0, 0, 0, 0)
    const todayLogs = callLogs.filter((l: any) => {
      try { return new Date(l.call_start) >= todayStart } catch { return false }
    })
    let todayAttempts = 0, todayConversations = 0
    todayLogs.forEach((l: any) => {
      const dur = Number(l.duration_seconds || 0)
      if (l.call_type === 'conversation' || (!l.call_type && dur > 180)) todayConversations++
      else todayAttempts++
    })

    return {
      calls: filteredLogs.length,
      avgDuration,
      meetings,
      pathCounts: paths,
      conversionByPath,
      outcomeCounts: outcomes,
      callerLeaderboard: leaderboard,
      todayAttempts,
      todayConversations
    }
  }, [filteredLogs, callLogs])

  // ÔöÇÔöÇ Actionable Follow-ups ÔöÇÔöÇ
  const actionableLogs = useMemo(() => {
    return callLogs
      .filter((log: any) => ['needs_follow_up', 'callback_scheduled', 'interested_will_revert'].includes(log.outcome))
      .sort((a: any, b: any) => new Date(b.call_start).getTime() - new Date(a.call_start).getTime())
  }, [callLogs])

  // ÔöÇÔöÇ CSV Export ÔöÇÔöÇ
  const handleExport = () => {
    if (!filteredLogs.length) return

    const headers = ['Date', 'Client', 'Caller', 'Path', 'Outcome', 'Duration (s)', 'Notes', 'Pipeline Auto-Advanced', 'Points Checked', 'Total Points']
    const csvContent = [
      headers.join(','),
      ...filteredLogs.map(log => {
        let ptsChecked = 0
        try { ptsChecked = JSON.parse(log.talking_points_checked || '[]').length } catch {}

        return [
          `"${new Date(log.call_start).toISOString()}"`,
          `"${(log.client_name || '').replace(/"/g, '""')}"`,
          `"${(log.caller_name || log.caller_email || '').replace(/"/g, '""')}"`,
          `"${(PATH_LABELS[log.path_loaded] || log.path_loaded || '').replace(/"/g, '""')}"`,
          `"${(OUTCOME_LABELS[log.outcome] || log.outcome || '').replace(/"/g, '""')}"`,
          log.duration_seconds || 0,
          `"${(log.call_notes || '').replace(/"/g, '""').replace(/\n/g, ' ')}"`,
          `"${(log.pipeline_auto_advanced || '').replace(/"/g, '""')}"`,
          ptsChecked,
          log.talking_points_total || 0
        ].join(',')
      })
    ].join('\n')

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' })
    const link = document.createElement('a')
    link.href = URL.createObjectURL(blob)
    link.download = `icuni_call_report_${dateFilter}_${new Date().getTime()}.csv`
    link.click()
  }

  return (
    <div className="crm-fade-in p-3 sm:p-6 h-full flex flex-col">
      {/* Header & Filters */}
      <div className="flex flex-col gap-3 sm:gap-4 mb-6 sm:mb-8">
        <div>
          <h2 className="text-2xl font-bold text-white flex items-center gap-2">
            <Phone className="w-6 h-6 text-[#00bfff]" /> Call Dashboard
          </h2>
          <p className="text-sm text-neutral-400 mt-1">Advanced analytics and call activity monitoring.</p>
        </div>

        <div className="flex flex-wrap items-center gap-2 sm:gap-3 bg-neutral-900/50 p-2 rounded-xl border border-neutral-800">
          <div className="flex items-center gap-2 sm:pr-4 sm:border-r sm:border-neutral-800">
            <Calendar className="w-4 h-4 text-neutral-500" />
            <select 
              value={dateFilter} 
              onChange={e => setDateFilter(e.target.value as DateFilter)}
              className="bg-transparent text-sm text-white font-medium outline-none cursor-pointer"
            >
              <option value="today">Today</option>
              <option value="yesterday">Yesterday</option>
              <option value="this_week">This Week</option>
              <option value="last_week">Last Week</option>
