                      </div>
                    </div>

                    {/* Buyer Profile */}
                    <div style={{ marginTop: 16 }}>
                      <p className="le-field-label" style={{ marginBottom: 8 }}>Buyer Profile (optional)</p>
                      <div className="le-persona-grid">
