import { useState, useEffect } from 'react'
import { AnimatePresence } from 'framer-motion'
import { useAdminStore, adminActions } from '../../../store/useAdminStore'
import VercelSidebar from './VercelSidebar'
import VercelTopbar from './VercelTopbar'
import { MenuIcon, CloseIcon, UserCircleIcon, EyeIcon } from './VercelIcons'
import './vercel-admin.css'

// Import existing section components ÔÇö zero modification
import AdminLogin from '../AdminLogin'
import DashboardSection from '../DashboardSection'
import MailSection from '../MailSection'
import CallSection from '../CallSection'
import CRMSection from '../CRMSection'
import AnalyticsSection from '../AnalyticsSection'
import { ProjectsSection, InvoicesSection, CareersSection, ReferralsSection, UsersSection, LogsSection } from '../AdminSections'
import SLASection from '../SLASection'
import ProfileSection from '../ProfileSection'
