import MeetingsSection from '../MeetingsSection'
import NewProjectSection from '../NewProjectSection'
import ContractsSection from '../ContractsSection'

interface VercelAdminShellProps {
  onSwitchTheme: () => void
}

export default function VercelAdminShell({ onSwitchTheme }: VercelAdminShellProps) {
  const { token, user, activeSection, actingAs, impersonating, users } = useAdminStore()

  const [collapsed, setCollapsed] = useState(() => {
    return localStorage.getItem('v_sidebar_collapsed') === 'true'
  })
  const [mobileOpen, setMobileOpen] = useState(false)
  const [showOnboarding, setShowOnboarding] = useState(false)
  const [showActAs, setShowActAs] = useState(false)
  const [showImpersonate, setShowImpersonate] = useState(false)
  const [darkMode, setDarkMode] = useState(() => {
    return localStorage.getItem('v_modern_dark') === 'true'
  })

  // Persist sidebar collapse
  useEffect(() => {
    localStorage.setItem('v_sidebar_collapsed', String(collapsed))
  }, [collapsed])

  // Persist dark mode
  useEffect(() => {
    localStorage.setItem('v_modern_dark', String(darkMode))
  }, [darkMode])

  // Validate session
  useEffect(() => { adminActions.validateSession() }, [])

  // If not logged in, show login within Modern theme wrapper
  if (!token || !user) {
    return (
      <div className={`vercel-theme ${darkMode ? 'v-dark' : ''}`}>
        <AdminLogin />
      </div>
    )
  }

  // Act As mode ÔÇö render target portal with banner
  if (actingAs === 'referrer') {
    return (
      <div className={`vercel-theme ${darkMode ? 'v-dark' : ''}`}>
        <div className="v-banner v-banner-actas">
          <EyeIcon size={16} />
          <span>Viewing as Referrer</span>
          <button onClick={() => adminActions.clearImpersonation()}>Exit</button>
        </div>
        <ReferralPortal demoMode />
      </div>
    )
  }
  if (actingAs === 'client') {
    return (
      <div className={`vercel-theme ${darkMode ? 'v-dark' : ''}`}>
        <div className="v-banner v-banner-actas">
          <EyeIcon size={16} />
          <span>Viewing as Client</span>
          <button onClick={() => adminActions.clearImpersonation()}>Exit</button>
        </div>
        <ClientPortal demoMode />
      </div>
    )
  }

  const sidebarWidth = collapsed ? 60 : 240

  const renderSection = () => {
    switch (activeSection) {
      case 'dashboard': return <DashboardSection />
      case 'analytics': return <AnalyticsSection />
      case 'mail': return <MailSection />
      case 'calls': return <CallSection />
      case 'clients': return <CRMSection />
      case 'projects': return <ProjectsSection />
      case 'invoices': return <InvoicesSection />
      case 'careers': return <CareersSection />
      case 'referrals': return <ReferralsSection />
      case 'sla': return <SLASection />
      case 'users': return <UsersSection />
      case 'logs': return <LogsSection />
      case 'settings': return <SettingsSection />
      case 'profile': return <ProfileSection />
      case 'ecosystem': return <EcosystemSection />
      case 'starterclass': return <StarterclassSection />
      case 'meetings': return <MeetingsSection />
      case 'new-project': return <NewProjectSection />
      case 'contracts': return <ContractsSection />
      default: return <DashboardSection />
    }
  }

  return (
    <div className={`vercel-theme ${darkMode ? 'v-dark' : ''}`}>
      {/* Mobile overlay */}
      {mobileOpen && (
        <div
          className="v-mobile-overlay"
          style={{
            position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.4)',
            zIndex: 39, cursor: 'pointer',
          }}
          onClick={() => setMobileOpen(false)}
        />
      )}

      {/* Mobile hamburger */}
      <button
        className="v-mobile-hamburger"
        onClick={() => setMobileOpen(!mobileOpen)}
        style={{
          position: 'fixed', top: 8, left: 8, zIndex: 50,
          width: 36, height: 36, display: 'flex', alignItems: 'center', justifyContent: 'center',
          borderRadius: 'var(--v-radius)', background: 'var(--v-surface)',
          border: '1px solid var(--v-border)', cursor: 'pointer',
          color: 'var(--v-text-secondary)',
        }}
        aria-label={mobileOpen ? 'Close menu' : 'Open menu'}
      >
        {mobileOpen ? <CloseIcon size={18} /> : <MenuIcon size={18} />}
      </button>

      {/* Sidebar */}
      <VercelSidebar
        collapsed={collapsed}
        onToggleCollapse={() => setCollapsed(!collapsed)}
        mobileOpen={mobileOpen}
        onCloseMobile={() => setMobileOpen(false)}
        onSwitchTheme={onSwitchTheme}
        onShowOnboarding={() => setShowOnboarding(true)}
        darkMode={darkMode}
        onToggleDarkMode={() => setDarkMode(!darkMode)}
      />

      {/* Main content */}
      <main
        className="v-main"
        style={{ marginLeft: `${sidebarWidth}px` }}
      >
        {/* CSS override for mobile */}
        <style>{`@media (max-width: 768px) { .v-main { margin-left: 0 !important; } }`}</style>

        {/* Top bar */}
        <VercelTopbar
          onShowActAs={() => { setShowActAs(!showActAs); setShowImpersonate(false) }}
          onShowImpersonate={() => {
            setShowImpersonate(!showImpersonate)
            setShowActAs(false)
            if (!users.length) adminActions.loadUsers()
          }}
          showActAs={showActAs}
          showImpersonate={showImpersonate}
        />

        {/* Content */}
        <div className="v-content">
          {renderSection()}
        </div>
      </main>

      {/* Impersonate Picker Modal */}
      {showImpersonate && (
        <div
          style={{
            position: 'fixed', inset: 0, zIndex: 50,
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            background: 'rgba(0,0,0,0.4)', backdropFilter: 'blur(4px)',
          }}
          onClick={() => setShowImpersonate(false)}
        >
          <div
            style={{
              background: 'var(--v-surface)', border: '1px solid var(--v-border)',
              borderRadius: 12, width: '100%', maxWidth: 420, padding: 24,
              boxShadow: 'var(--v-shadow)',
            }}
            onClick={e => e.stopPropagation()}
          >
            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 16 }}>
              <h3 style={{ fontSize: 16, fontWeight: 700, color: 'var(--v-text)', display: 'flex', alignItems: 'center', gap: 8 }}>
                <UserCircleIcon size={20} />
                Impersonate User
              </h3>
              <button
                onClick={() => setShowImpersonate(false)}
                style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--v-text-tertiary)', padding: 4 }}
              >
                <CloseIcon size={18} />
              </button>
            </div>
            <p style={{ fontSize: 12, color: 'var(--v-text-tertiary)', marginBottom: 16 }}>
              View the app as this user sees it. Useful for demoing and troubleshooting.
            </p>
            <div style={{ maxHeight: 256, overflowY: 'auto' }}>
              {users.length === 0 ? (
                <p style={{ fontSize: 13, color: 'var(--v-text-tertiary)', textAlign: 'center', padding: 16 }}>Loading users...</p>
              ) : (
                users.map((u: any) => (
                  <button
                    key={u.id}
                    onClick={() => { adminActions.setImpersonating(u); setShowImpersonate(false); adminActions.setSection('profile') }}
                    style={{
                      width: '100%', display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                      padding: 12, borderRadius: 'var(--v-radius)', background: 'none', border: 'none',
                      cursor: 'pointer', textAlign: 'left', transition: 'background 150ms',
                    }}
                    onMouseEnter={e => (e.currentTarget.style.background = 'var(--v-hover)')}
                    onMouseLeave={e => (e.currentTarget.style.background = 'none')}
                  >
                    <div>
                      <p style={{ fontSize: 13, fontWeight: 500, color: 'var(--v-text)' }}>{u.name}</p>
                      <p style={{ fontSize: 11, color: 'var(--v-text-tertiary)' }}>{u.email}</p>
                    </div>
                    <span style={{
                      fontSize: 10, fontWeight: 700, textTransform: 'uppercase' as const, letterSpacing: 0.5,
                      padding: '2px 8px', borderRadius: 99,
                      color: u.role === 'Godmode' ? '#f5a623' : u.role === 'SuperAdmin' ? '#d97706' : 'var(--v-accent)',
                      background: u.role === 'Godmode' ? 'rgba(245,166,35,0.1)' : u.role === 'SuperAdmin' ? 'rgba(217,119,6,0.1)' : 'var(--v-accent-light)',
                    }}>{u.role}</span>
                  </button>
                ))
              )}
            </div>
          </div>
        </div>
      )}

      {/* Impersonating Banner */}
      {impersonating && (
        <div className="v-banner v-banner-impersonate">
          <UserCircleIcon size={16} />
          <span>Impersonating: {impersonating.name} ({impersonating.role})</span>
          <button onClick={() => adminActions.clearImpersonation()}>Exit</button>
        </div>
      )}

      {/* Onboarding Checklist */}
      <AnimatePresence>
        {showOnboarding && (
          <OnboardingChecklist
            onClose={() => setShowOnboarding(false)}
            onNavigate={(section: string) => adminActions.setSection(section)}
          />
        )}
      </AnimatePresence>

      {/* Floating Call Bubble ÔÇö persists across all sections */}
      <FloatingCallBubble />
    </div>
  )
}

/**
 * VercelSidebar ÔÇö Vercel-inspired navigation sidebar for the Modern admin theme.
 * Uses custom SVG icons from VercelIcons.tsx. Supports collapse, search, and role-based nav.
 */
import { useState, useMemo } from 'react'
import { useAdminStore, adminActions } from '../../../store/useAdminStore'
import {
  DashboardIcon, MailIcon, ClientsIcon, ReferralsIcon, InvoicesIcon,
  SLAIcon, TeamIcon, EcosystemIcon, StarterclassIcon, CareersIcon,
  LogsIcon, SettingsIcon, SearchIcon, LogoutIcon,
  SidebarCollapseIcon, SidebarExpandIcon, ThemeIcon,
  OnboardingIcon, ICUNILogo, SunIcon, MoonIcon,
  PhoneIcon, AnalyticsIcon, MeetingsIcon, NewProjectIcon, ContractsIcon,
} from './VercelIcons'

export interface NavItem {
  id: string
  label: string
  icon: React.FC<{ className?: string; size?: number }>
  section?: string  // group label
}

export const SIDEBAR_CONFIG_KEY = 'icuni_sidebar_config'

export const DEFAULT_NAV_ITEMS: NavItem[] = [
  // Overview
  { id: 'dashboard', label: 'Dashboard', icon: DashboardIcon, section: 'Overview' },
  { id: 'analytics', label: 'Analytics', icon: AnalyticsIcon },
  // Operations
  { id: 'clients', label: 'Clients', icon: ClientsIcon, section: 'Operations' },
  { id: 'calls', label: 'Calls', icon: PhoneIcon },
  { id: 'meetings', label: 'Meetings', icon: MeetingsIcon },
  { id: 'mail', label: 'Mail Hub', icon: MailIcon },
  { id: 'invoices', label: 'Invoices', icon: InvoicesIcon },
  // Projects
  { id: 'new-project', label: 'New Project', icon: NewProjectIcon, section: 'Projects' },
  { id: 'contracts', label: 'Contracts', icon: ContractsIcon },
  { id: 'ecosystem', label: 'Ecosystem', icon: EcosystemIcon },
  // Management
  { id: 'users', label: 'Team', icon: TeamIcon, section: 'Management' },
  { id: 'starterclass', label: 'Starterclass', icon: StarterclassIcon },
  { id: 'careers', label: 'Careers', icon: CareersIcon },
  { id: 'referrals', label: 'Referrals', icon: ReferralsIcon },
  // Admin
  { id: 'sla', label: 'SLA Tracker', icon: SLAIcon, section: 'Admin' },
  { id: 'logs', label: 'Logs', icon: LogsIcon },
  { id: 'settings', label: 'Settings', icon: SettingsIcon },
]

interface VercelSidebarProps {
  collapsed: boolean
  onToggleCollapse: () => void
  mobileOpen: boolean
  onCloseMobile: () => void
  onSwitchTheme: () => void
  onShowOnboarding: () => void
  darkMode: boolean
  onToggleDarkMode: () => void
}

export default function VercelSidebar({
  collapsed, onToggleCollapse, mobileOpen, onCloseMobile,
  onSwitchTheme, onShowOnboarding, darkMode, onToggleDarkMode,
}: VercelSidebarProps) {
  const { activeSection, user, impersonating } = useAdminStore()
  const [searchQuery, setSearchQuery] = useState('')

  // When impersonating, filter sidebar by the IMPERSONATED user's role
  const effectiveRole = impersonating ? (impersonating.role || '') : (user?.role || '')
  const role = effectiveRole
  const isElevated = ['Godmode', 'SuperAdmin'].includes(role)

  // Department scope mapping
  const DEPT_SCOPE: Record<string, string[]> = {
    'Admin': ['dashboard', 'mail', 'clients', 'calls', 'meetings', 'referrals', 'invoices', 'sla', 'new-project', 'contracts', 'ecosystem', 'settings'],
    'Sales': ['dashboard', 'analytics', 'mail', 'clients', 'calls', 'meetings', 'sla'],
    'Product': ['dashboard', 'mail', 'new-project', 'contracts', 'ecosystem', 'sla'],
  }

  const userPerms = user?.permissions || {}

  // Apply saved sidebar config (reorder + rename)
  const resolvedNav = useMemo(() => {
    try {
      const raw = localStorage.getItem(SIDEBAR_CONFIG_KEY)
      if (!raw) return DEFAULT_NAV_ITEMS
      const config: { id: string; label: string; section?: string }[] = JSON.parse(raw)
      // Map saved config onto real items (preserving icons)
      const iconMap: Record<string, React.FC<{ className?: string; size?: number }>> = {}
      DEFAULT_NAV_ITEMS.forEach(n => { iconMap[n.id] = n.icon })
      const result: NavItem[] = config
        .filter(c => iconMap[c.id])
        .map(c => ({ id: c.id, label: c.label, icon: iconMap[c.id], section: c.section }))
      // Add any new default items not in saved config
      DEFAULT_NAV_ITEMS.forEach(n => {
        if (!result.find(r => r.id === n.id)) result.push(n)
      })
      return result
    } catch { return DEFAULT_NAV_ITEMS }
  }, [])

  // Filter nav items by role
  const filteredNav = resolvedNav.filter(item => {
    if (role === 'Godmode') return true
    if (item.id === 'users') return isElevated
    if (item.id === 'ecosystem') return isElevated
    if (item.id === 'starterclass') return isElevated
    if (item.id === 'careers') return false
    if (item.id === 'logs') return false
    if (role === 'SuperAdmin') return true
    const deptSections = DEPT_SCOPE[role] || []
    const inScope = deptSections.includes(item.id)
    if (userPerms[item.id] === false) return false
    return inScope
  })

  // Filter by search
  const searchFiltered = searchQuery
    ? filteredNav.filter(item => item.label.toLowerCase().includes(searchQuery.toLowerCase()))
    : filteredNav

  // Group items by section
  const groupedNav: { section: string; items: NavItem[] }[] = []
  let currentSection = ''
  searchFiltered.forEach(item => {
    if (item.section && item.section !== currentSection) {
      currentSection = item.section
      groupedNav.push({ section: currentSection, items: [item] })
    } else {
      if (groupedNav.length === 0) groupedNav.push({ section: '', items: [] })
      groupedNav[groupedNav.length - 1].items.push(item)
    }
  })

  const effectiveUser = impersonating || user
  const userPic = effectiveUser?.profile_pic_url || ''

  const handleNavClick = (id: string) => {
    adminActions.setSection(id)
    adminActions.setError('')
    onCloseMobile()
  }

  return (
    <aside className={`v-sidebar ${collapsed ? 'collapsed' : ''} ${mobileOpen ? 'mobile-open' : ''}`}>
      {/* Header ÔÇö Logo + Project name */}
      <div className="v-sidebar-header">
        <ICUNILogo size={22} />
        {!collapsed && (
          <>
            <span className="v-project-name">ICUNI Labs</span>
            <span className="v-project-badge">Ops</span>
          </>
        )}
      </div>

      {/* Search */}
      {!collapsed && (
        <div className="v-sidebar-search">
          <div className="v-sidebar-search-wrapper">
            <SearchIcon size={14} />
            <input
              type="text"
              placeholder="Search..."
              value={searchQuery}
              onChange={e => setSearchQuery(e.target.value)}
            />
            <span className="v-shortcut">Ctrl+K</span>
          </div>
        </div>
      )}

      {/* Navigation */}
      <nav className="v-nav">
        {groupedNav.map((group, gi) => (
          <div key={gi} className="v-nav-section">
            {group.section && !collapsed && (
              <div className="v-nav-section-label">{group.section}</div>
            )}
            {group.items.map(item => {
              const isActive = activeSection === item.id
              return (
                <button
                  key={item.id}
                  onClick={() => handleNavClick(item.id)}
                  className={`v-nav-item ${isActive ? 'active' : ''}`}
                  title={collapsed ? item.label : undefined}
                  aria-label={item.label}
                >
                  <item.icon className="v-nav-icon" size={18} />
                  {!collapsed && <span>{item.label}</span>}
                </button>
              )
            })}
          </div>
        ))}
      </nav>

      {/* Footer ÔÇö User + Actions */}
      <div className="v-sidebar-footer">
        {/* Profile button */}
        <button
          onClick={() => handleNavClick('profile')}
          className="v-user-btn"
          title="Profile"
        >
          <div className="v-user-avatar">
            {userPic ? (
              <img src={userPic} alt="" />
            ) : (
              <svg width="16" height="16" viewBox="0 0 20 20" fill="none" stroke="currentColor" strokeWidth="1.3">
                <circle cx="10" cy="7" r="3.5" />
                <path d="M3.5 17c0-3.6 2.9-6.5 6.5-6.5s6.5 2.9 6.5 6.5" strokeLinecap="round" />
              </svg>
            )}
          </div>
          {!collapsed && (
            <div className="v-user-info">
              <div className="v-user-name">{effectiveUser?.name || user?.name}</div>
              <div className="v-user-email">{effectiveUser?.company_email || effectiveUser?.email}</div>
            </div>
          )}
        </button>

        {/* Dark/Light mode toggle */}
        <button onClick={onToggleDarkMode} className="v-theme-toggle" title={darkMode ? 'Switch to light mode' : 'Switch to dark mode'}>
          {darkMode ? <SunIcon size={15} /> : <MoonIcon size={15} />}
          {!collapsed && <span>{darkMode ? 'Light Mode' : 'Dark Mode'}</span>}
        </button>

        {/* Onboarding */}
        <button onClick={onShowOnboarding} className="v-theme-toggle" title="Onboarding">
          <OnboardingIcon size={15} />
          {!collapsed && <span>Onboarding</span>}
        </button>

        {/* Switch to Classic theme */}
        <button onClick={onSwitchTheme} className="v-theme-toggle" title="Switch to Classic theme">
          <ThemeIcon size={15} />
          {!collapsed && <span>Classic View</span>}
        </button>

        {/* Logout */}
        <button
          onClick={() => { adminActions.logout(); window.history.pushState({}, '', '/'); window.dispatchEvent(new PopStateEvent('popstate')); }}
          className="v-action-btn danger"
          style={{ width: '100%' }}
        >
          <LogoutIcon size={15} />
          {!collapsed && <span>Logout</span>}
        </button>

        {/* Collapse toggle ÔÇö desktop only */}
        <button
          onClick={onToggleCollapse}
          className="v-theme-toggle"
          title={collapsed ? 'Expand sidebar' : 'Collapse sidebar'}
          style={{ display: 'none' }}
          id="v-collapse-desktop"
        >
          {collapsed ? <SidebarExpandIcon size={15} /> : <SidebarCollapseIcon size={15} />}
          {!collapsed && <span>Collapse</span>}
        </button>
      </div>

      {/* Desktop collapse strip ÔÇö right edge */}
      <button
        onClick={onToggleCollapse}
        className="v-collapse-strip"
        title={collapsed ? 'Expand sidebar' : 'Collapse sidebar'}
        aria-label={collapsed ? 'Expand sidebar' : 'Collapse sidebar'}
        style={{
          position: 'absolute',
          right: 0,
          top: 0,
          bottom: 0,
          width: 4,
          cursor: 'col-resize',
          background: 'transparent',
          border: 'none',
          padding: 0,
          zIndex: 10,
          transition: 'background 150ms',
        }}
        onMouseEnter={e => (e.currentTarget.style.background = 'var(--v-accent)')}
        onMouseLeave={e => (e.currentTarget.style.background = 'transparent')}
      />
    </aside>
  )
}

import { motion, useScroll, useTransform, useSpring } from 'framer-motion';
import { useRef, useMemo } from 'react';

/**
 * ScrollBackground Component - "Chaos to System" (Holographic HUD Edition)
 * 
 * Narrative:
 * 1. Top: Floating papers, WhatsApp chats, chaos elements drift around.
 * 2. Transition: They digitize/morph as user scrolls.
 * 3. Bottom: Full Holographic System Interface (HUD style).
 */
export default function ScrollBackground() {
    const containerRef = useRef<HTMLDivElement>(null);
    const { scrollYProgress } = useScroll();

    const smoothProgress = useSpring(scrollYProgress, {
        stiffness: 150,
        damping: 30,
        restDelta: 0.001
    });

    // Generate Layout Data (The "System" Dashboard)
    const systemLayouts = [
        { l: 15, t: 20, w: 70, h: 10, type: 'header' },
        { l: 15, t: 35, w: 15, h: 35, type: 'sidebar' },
        { l: 35, t: 35, w: 30, h: 35, type: 'module' },
        { l: 70, t: 35, w: 15, h: 35, type: 'module' },
        { l: 15, t: 75, w: 70, h: 10, type: 'footer' },
    ];

    const papers = useMemo(() => {
        return systemLayouts.map((layout, i) => ({
            id: i,
            isSystem: true,
            initialLeft: (Math.sin(i * 123.45) * 0.5 + 0.5) * 50 + 25,
            initialTop: (Math.cos(i * 321.12) * 0.5 + 0.5) * 70 + 5,
            initialRotate: Math.sin(i * 456.78) * 45,
            finalLeft: layout.l,
            finalTop: layout.t,
            finalWidth: layout.w,
            finalHeight: layout.h,
            type: layout.type,
            // Unique float params for idle animation
            floatDuration: 6 + (i % 3) * 2,
            floatX: 8 + (i % 4) * 4,
            floatY: 6 + (i % 3) * 3,
            floatDelay: i * 0.8,
        }));
    }, []);

    // Chaos elements (WhatsApp chats, notifications, sticky notes) ÔÇö pushed to edges
    const chaosItems = useMemo(() => [
        { id: 'wa1', type: 'whatsapp', x: 3, y: 8, dur: 7, dx: 5, dy: 4, rot: -12 },
        { id: 'wa2', type: 'whatsapp', x: 80, y: 18, dur: 8, dx: -4, dy: 6, rot: 8 },
        { id: 'wa3', type: 'whatsapp', x: 5, y: 72, dur: 9, dx: 6, dy: -3, rot: -5 },
        { id: 'n1', type: 'sticky', x: 88, y: 60, dur: 7.5, dx: -3, dy: 5, rot: 15 },
        { id: 'n2', type: 'sticky', x: 2, y: 45, dur: 6.5, dx: 4, dy: -4, rot: -20 },
        { id: 'e1', type: 'email', x: 82, y: 5, dur: 8.5, dx: -5, dy: 3, rot: 6 },
        { id: 'e2', type: 'email', x: 85, y: 78, dur: 7, dx: 3, dy: -5, rot: -8 },
    ], []);

    const systemProgress = useTransform(smoothProgress, [0, 0.85], [0, 1]);
    const gridOpacity = useTransform(systemProgress, [0.5, 1], [0, 1]);
    const chaosOpacity = useTransform(systemProgress, [0, 0.3], [1, 0]);

    return (
        <div
            ref={containerRef}
            className="fixed inset-0 z-0 pointer-events-none overflow-hidden"
            aria-hidden="true"
        >
            {/* BACKGROUND GRID (Only appears in System Mode) */}
            <div className="absolute inset-0 w-full h-full">
                <svg className="w-full h-full">
                    <defs>
                        <pattern id="small-grid" width="40" height="40" patternUnits="userSpaceOnUse">
                            <path d="M 40 0 L 0 0 0 40" fill="none" stroke="rgba(0, 191, 255, 0.1)" strokeWidth="0.5" />
                        </pattern>
                    </defs>
                    <motion.rect width="100%" height="100%" fill="url(#small-grid)" style={{ opacity: gridOpacity }} />
                </svg>
            </div>

            {/* CENTER VIGNETTE ÔÇö protects hero text from chaos clutter */}
            <div className="absolute inset-0 z-[1]" style={{
                background: 'radial-gradient(ellipse 50% 60% at 50% 45%, rgba(10,10,10,0.95) 0%, rgba(10,10,10,0.7) 40%, transparent 70%)'
            }} />

            {/* FLOATING CHAOS ELEMENTS (WhatsApp chats, emails, sticky notes) */}
            {chaosItems.map((c) => (
                <motion.div key={c.id}
                    className="absolute"
                    style={{
                        left: `${c.x}%`, top: `${c.y}%`,
                        opacity: chaosOpacity,
                    }}
                    animate={{
                        x: [0, c.dx, -c.dx * 0.5, c.dx * 0.3, 0],
                        y: [0, c.dy, -c.dy * 0.5, c.dy * 0.7, 0],
                        rotate: [c.rot, c.rot + 3, c.rot - 2, c.rot],
                        scale: [0.65, 0.7, 0.65],
                    }}
                    transition={{ duration: c.dur, repeat: Infinity, ease: 'easeInOut' }}
                >
                    {c.type === 'whatsapp' && <WhatsAppBubble />}
                    {c.type === 'sticky' && <StickyNote />}
                    {c.type === 'email' && <EmailIcon />}
                </motion.div>
            ))}

            {/* CONNECTING LINES (The "Network") */}
            <svg className="absolute inset-0 w-full h-full">
                <motion.g style={{ opacity: useTransform(systemProgress, [0.6, 1], [0, 1]) }}>
                    <line x1="30%" y1="52%" x2="35%" y2="52%" stroke="rgba(0, 191, 255, 0.6)" strokeWidth="1" strokeDasharray="2 2" />
                    <line x1="65%" y1="52%" x2="70%" y2="52%" stroke="rgba(0, 191, 255, 0.6)" strokeWidth="1" strokeDasharray="2 2" />
                    <line x1="50%" y1="30%" x2="50%" y2="35%" stroke="rgba(0, 191, 255, 0.6)" strokeWidth="1" strokeDasharray="2 2" />
                    <line x1="50%" y1="70%" x2="50%" y2="75%" stroke="rgba(0, 191, 255, 0.6)" strokeWidth="1" strokeDasharray="2 2" />
