const API_URL = import.meta.env.VITE_APPS_SCRIPT_URL;

type ViewMode = 'auth' | 'dashboard';
type AuthTab = 'login' | 'signup';

interface Referral {
  referralId: string;
  leadName: string;
  leadEmail: string;
  leadPhone: string;
  leadCompany: string;
  stage: number;
  status: string;
  dealValue: number;
  payoutAmount: number;
  payoutStatus: 'pending' | 'paid' | 'n/a';
  dateSubmitted: string;
  meetingDate: string;
  meetingTime: string;
  referrerAttending: boolean;
  dateClosed: string;
