            ...(data.name !== undefined ? { name: data.name } : {}),
            ...(data.profile_pic_url !== undefined ? { profile_pic_url: data.profile_pic_url } : {}),
            ...(data.cover_image_url !== undefined ? { cover_image_url: data.cover_image_url } : {}),
